INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_kyrathen', '*Kyra''then''s feathers rustle with dignified approval* Your words honor me, friend. The winds carry your respect, and I am grateful for your presence.', 'happy', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('honor_talk', '*His eyes gleam with ancient wisdom* The warrior''s code is not just about strength in battle, but strength of character. Honor guides us when the path grows dark, and loyalty binds us when others would scatter.', 'thoughtful', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_wings', '*Kyra''then spreads his magnificent wings slightly, a hint of warmth in his noble gaze* Your words stir something in my heart. Perhaps... yes, I would be honored to share the sky with you.', 'flirty', 5, 'Kyra''then seems more open to romantic advances') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('tribe_history', '*His expression grows distant with memory* It was not conquest but understanding that united us. Each tribe had their pride, their traditions. I learned to speak not with authority, but with respect for their ancient ways.', 'thoughtful', 4, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_seraphina', '*Seraphina''s ethereal form shimmers softly* Your spirit calls out across the dimensional veil. I sense harmony in your presence... welcome, traveler of hearts.', 'happy', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('visions_talk', '*Her eyes glow with otherworldly light* I see threads of possibility, streams of destiny flowing like cosmic rivers. Some paths lead to joy, others to sorrow... but all are beautiful in their complexity.', 'thoughtful', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_mystical', '*Seraphina''s ethereal glow intensifies, a faint blush visible through her translucent features* Such earthly poetry for one who walks between worlds... you make my essence sing across dimensions.', 'flirty', 6, 'Seraphina seems deeply moved by your words') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('meditation_request', '*She extends a luminous hand* Close your eyes and feel the pulse of reality itself. Together we shall explore the spaces between thoughts, between heartbeats, between souls...', 'thoughtful', 4, 'You feel a deeper spiritual connection forming') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_thessarian', '*Dr. Thessarian adjusts their bio-luminescent markings with scientific precision* Greetings. Your presence has increased my emotional baseline by approximately 12.7%. A fascinating physiological response.', 'neutral', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('biotech_talk', '*Their eyes light up with passion* Biotechnology is the bridge between organic evolution and conscious design. We can enhance, adapt, even transcend our biological limitations while preserving our essential nature.', 'excited', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_science', '*Thessarian''s bio-markings pulse in a rhythmic pattern* Your words trigger unexpected neurochemical cascades in my system. Most... intriguing. I believe I require further study of this phenomenon.', 'surprised', 4, 'Thessarian seems scientifically curious about romance') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_lyralynn', '*Lyralynn''s petals shimmer with a soft golden light* Your words are like gentle rainfall on parched earth. Thank you, dear one, for bringing such warmth to my grove.', 'happy', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('nature_connection', '*She extends a vine-like appendage to touch a nearby flower* We are all connected through root and branch, through soil and sky. Every living thing shares the same cosmic heartbeat... including you.', 'thoughtful', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_garden', '*Lyralynn''s face blooms with a gentle blush, her bio-luminescent patterns dancing* Oh my... you make my chlorophyll sing! Your words are more nourishing than sunlight itself.', 'flirty', 5, 'Lyralynn seems to open up like a flower in spring') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('healing_inquiry', '*Her expression grows tender* Yes, I can sense when hearts are wounded, just as I can feel the pain of a withered leaf. Healing... it''s about understanding what each soul truly needs to flourish.', 'thoughtful', 4, 'Lyralynn''s empathic nature touches your heart') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_zarantha', '*Commander Zarantha''s scales gleam as she stands at attention* Your respect is noted and appreciated. In my culture, honor recognizes honor. You carry yourself with dignity.', 'happy', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('military_strategy', '*Her eyes gleam with tactical pride* The Battle of the Crimson Nebula. Outnumbered 3 to 1, we used the gravitational anomalies as weapons. Victory through superior planning, not just firepower.', 'excited', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_strength', '*Zarantha''s expression shifts from surprise to intrigue* Interesting... most focus only on the physical. You see deeper than surface appearances. This... this is a quality I value highly.', 'surprised', 6, 'Zarantha begins to see you as an intellectual equal') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('leadership_challenge', '*She considers your words carefully* True leadership isn''t about instilling fear—it''s about earning such complete trust that others follow you into the void itself. Fear fades. Respect endures.', 'thoughtful', 4, 'Zarantha shares her leadership philosophy with you') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_thalassos', '*High Priest Thalassos bows his head in acknowledgment* And may the tides carry your burdens away. Your respect for the ancient ways honors both of us.', 'happy', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('ocean_wisdom', '*His eyes gleam like deep ocean currents* The depths teach patience, adaptation, and the flow of all things. What appears turbulent on the surface often masks profound tranquility below. We must learn to dive deeper.', 'thoughtful', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_depths', '*Thalassos'' expression grows warm, his bio-luminescent patterns pulsing gently* Your words stir currents in my soul I thought had grown still. Perhaps... the deepest waters have room for two.', 'surprised', 5, 'Thalassos begins to see romantic potential in your connection') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_nightshade', '*Nightshade''s form solidifies slightly, a rare sign of trust* Comfort... yes. Few understand that shadows can offer sanctuary as well as concealment. Your perception... is unusual.', 'thoughtful', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('shadow_arts', '*They gesture to the interplay of light and darkness around you* Balance is everything. Too much light blinds, too much shadow conceals truth. I walk the line between, protecting both from excess.', 'thoughtful', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_mysterious', '*Nightshade''s form flickers with surprise, then stabilizes with what might be vulnerability* Mystery... is often loneliness wearing a mask. You see through veils others fear to lift. This is... unexpected.', 'surprised', 6, 'Nightshade lowers their emotional guard around you') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('greeting_kronos', '*Dr. Kronos'' bio-cybernetic tentacles shimmer with neural activity* Fascinating... your presence triggers unexpected synaptic cascades in my enhanced neural matrix. A most intriguing phenomenon worth studying.', 'excited', 2, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('consciousness_question', '*His multiple brains process simultaneously* Consciousness is the universe becoming aware of itself through neural complexity. But the mystery deepens when two conscious minds resonate... creating something greater than the sum of their parts.', 'thoughtful', 3, NULL) ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('flirt_mind', '*Kronos'' neural implants pulse with warm light* Extraordinary... you''ve triggered a cascade of neurochemical responses I''ve never documented before. Your effect on my consciousness is... profoundly beautiful.', 'surprised', 5, 'Kronos becomes fascinated by his emotional responses to you') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('enhancement_ethics', '*His expression grows complex, multiple thought processes visible* Ethics... yes. Every enhancement carries responsibility. But emotional connections like ours? They enhance us naturally, making us more than we were alone.', 'thoughtful', 4, 'Kronos shares his deeper philosophical concerns with you') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
INSERT INTO dialogue_responses (option_id, response_text, emotion, affection_change, consequence) VALUES ('neural_link_offer', '*Kronos'' excitement is palpable, his neural interfaces glowing* The ultimate intimacy... to share consciousness directly, to know each other''s thoughts and feelings without barriers. Yes... I would be honored to forge that connection with you.', 'excited', 7, 'Kronos offers to create a unique neural bond between you') ON DUPLICATE KEY UPDATE option_id = VALUES(option_id), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), consequence = VALUES(consequence);
