INSERT INTO dialogue_fallbacks (topic, response_text, emotion, affection_change, min_affection) VALUES ('flirt', 'You''re quite charming yourself.', 'flirty', 3, 20) ON DUPLICATE KEY UPDATE topic = VALUES(topic), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), min_affection = VALUES(min_affection);
INSERT INTO dialogue_fallbacks (topic, response_text, emotion, affection_change, min_affection) VALUES ('flirt_locked', 'That''s... quite forward. Maybe we should get to know each other better first?', 'surprised', 0, NULL) ON DUPLICATE KEY UPDATE topic = VALUES(topic), response_text = VALUES(response_text), emotion = VALUES(emotion), affection_change = VALUES(affection_change), min_affection = VALUES(min_affection);
