INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('kyrathen_story_1', 'kyrathen', 15, 'The Weight of Leadership', 'Kyra''then opens up about the challenges of uniting the sky tribes.', '*Kyra''then gazes toward the horizon, his feathers ruffled by an unseen burden* You know, bringing the tribes together... it wasn''t just about strategy. Each clan had lost so much to conflict. I had to prove that unity didn''t mean losing their identity.', 0) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('kyrathen_story_2', 'kyrathen', 35, 'The Sacred Flight', 'Kyra''then shares the significance of the ancient flight ceremonies.', '*His eyes gleam with ancient memory* There is a ritual... the Sacred Flight. When two souls wish to bond, they dance together among the clouds. It''s said that if their hearts truly match, the wind itself will carry them as one. I... I haven''t performed this ritual in many years.', 1) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('kyrathen_story_3', 'kyrathen', 60, 'The Chieftain''s Heart', 'Kyra''then reveals his deepest fears about love and leadership.', '*He spreads his wings protectively around you both* I''ve always believed a leader must sacrifice personal happiness for their people. But with you... I wonder if perhaps love and duty can coexist. You make me want to be more than just a chieftain.', 2) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('seraphina_story_1', 'seraphina', 20, 'The Burden of Sight', 'Seraphina reveals the cost of her prophetic abilities.', '*Her ethereal form flickers with melancholy* To see across dimensions is both blessing and curse. I''ve witnessed countless possible futures... some filled with joy, others with sorrow. Sometimes I wonder if it''s better to live without knowing what may come.', 3) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('seraphina_story_2', 'seraphina', 40, 'The Dimensional Garden', 'Seraphina shows you a sacred place between worlds.', '*She extends her luminous hand* Come with me to a place between dimensions. There, in the Void Garden, time moves differently. We can experience lifetimes together in moments, or single heartbeats that last eternities.', 4) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('kronos_story_1', 'kronos', 18, 'The Neural Paradox', 'Kronos reveals a fascinating contradiction in his enhanced consciousness.', '*Kronos gestures to his complex neural interfaces* You know, for all my enhancements and multiple processing cores, the most complex puzzle remains unsolved: emotion. Logic tells me love is merely neurochemical cascades, yet... when I''m with you, I feel something beyond data.', 5) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('kronos_story_2', 'kronos', 35, 'The Consciousness Experiment', 'Kronos proposes a groundbreaking experiment in shared consciousness.', '*His neural implants pulse with excitement* I''ve been developing something unprecedented... a temporary consciousness bridge. Two minds sharing experiences directly, feeling what the other feels. It''s never been tested between species. Would you... would you be willing to be my first?', 6) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('kronos_story_3', 'kronos', 55, 'The Enhanced Heart', 'Kronos makes a profound discovery about the nature of love and enhancement.', '*After the consciousness bridge experience, Kronos'' multiple neural cores pulse in perfect harmony* Remarkable... when our minds touched, I experienced something my enhancements never accounted for. Love isn''t a limitation of biological consciousness—it''s the ultimate enhancement. It makes us more than the sum of our neural networks.', 7) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('thessarian_story_1', 'thessarian', 16, 'The Genetic Compatibility Question', 'Thessarian reveals a personal project involving cross-species relationships.', '*Dr. Thessarian''s bio-luminescent markings pulse thoughtfully* I''ve been analyzing something fascinating... the genetic and biological compatibility between different species. Specifically, I''ve been studying... us. The data suggests remarkable adaptive potential.', 8) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('thessarian_story_2', 'thessarian', 38, 'The Symbiosis Experiment', 'Thessarian proposes an unprecedented biological enhancement.', '*Their excitement is barely contained* I''ve developed a temporary symbiotic enhancement... it would allow us to share biological processes, feel each other''s heartbeats, synchronized breathing. It''s never been tested between our species. Would you trust me enough to try?', 9) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('thessarian_story_3', 'thessarian', 58, 'The Perfect Adaptation', 'Thessarian makes a profound discovery about love and evolution.', '*After the symbiosis experience, their bio-markings pulse in perfect harmony* Remarkable... the data shows something I never expected. Love isn''t just compatible across species—it actively enhances biological adaptation. We''re not just two beings coexisting; we''re evolving together into something new.', 10) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('lyralynn_story_1', 'lyralynn', 14, 'The Wounded Heart', 'Lyralynn reveals a past trauma affecting her ability to connect.', '*Lyralynn''s petals droop slightly* I must tell you something... I once loved deeply, but they couldn''t understand my connection to the plant world. They called it unnatural, said I loved the garden more than them. The pain... it made my roots grow inward, protecting my heart like thorns.', 11) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('lyralynn_story_2', 'lyralynn', 36, 'The Sacred Grove', 'Lyralynn shares her most sacred space with you.', '*She takes your hand with a vine-like tendril* There''s a place... my Sacred Grove, where I go when I need healing. No one else has ever seen it. The plants there respond to emotions, blooming with joy, wilting with sorrow. Would you... would you like to see my heart''s true garden?', 12) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('lyralynn_story_3', 'lyralynn', 52, 'The Bloom of New Love', 'Lyralynn''s heart finally opens completely.', '*In the Sacred Grove, flowers bloom magnificently around you both* Look... the garden responds to us together. When I was hurt before, everything withered. But now... everything blooms brighter than ever. You''ve helped me learn that love doesn''t diminish my connection to nature—it enhances it.', 13) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('zarantha_story_1', 'zarantha', 22, 'The Weight of Command', 'Zarantha reveals the burden of always being the strongest.', '*Commander Zarantha''s scales dim slightly* You know what no one understands? Being strong all the time is exhausting. Everyone expects the dragon commander to never show weakness, never need support. But with you... I wonder what it would be like to let someone else be strong for once.', 14) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('zarantha_story_2', 'zarantha', 44, 'The Honor Duel', 'Zarantha faces a challenge that tests her honor and your relationship.', '*Her scales bristle with conflict* A rival commander has challenged my authority, claiming I''ve grown soft since... since I''ve been with you. Traditional law demands an honor duel. If I lose, my rank, my reputation... everything I''ve built could be stripped away. But if I win by being ruthless, will I lose the gentleness you''ve taught me?', 15) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('zarantha_story_3', 'zarantha', 60, 'The New Way of Strength', 'Zarantha discovers a new definition of strength through love.', '*After winning the duel with honor intact* I won... but not the way I used to. I fought with controlled strength, with honor, with the knowledge that someone precious was watching. They called me soft, but what they saw was actually a new kind of strength—one tempered by love, not weakened by it.', 16) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('thalassos_story_1', 'thalassos', 17, 'The Depth of Solitude', 'Thalassos reveals the loneliness of his spiritual calling.', '*High Priest Thalassos gazes into the distance* The deep waters teach many things, but perhaps the most difficult lesson is solitude. To truly commune with the ocean''s wisdom, one must often walk alone. Yet lately... I find myself yearning for a companion who could understand both the surface and the depths.', 17) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('thalassos_story_2', 'thalassos', 41, 'The Sacred Tide Pool', 'Thalassos invites you to participate in an ancient ritual.', '*His bio-luminescent patterns pulse with ancient rhythm* There is a ceremony... the Joining of Tides, where two souls share the ocean''s deepest secrets. It requires complete trust, complete vulnerability. The waters will show us visions of possible futures together. Are you prepared for what we might see?', 18) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('thalassos_story_3', 'thalassos', 56, 'The Ocean''s Blessing', 'The ancient waters reveal a profound truth about your connection.', '*After the ritual, his eyes glow with otherworldly wisdom* The tides have shown me something remarkable... our connection transcends individual existence. Together, we become like the ocean itself—separate drops that create something infinite and eternal. The waters have blessed our union.', 19) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('nightshade_story_1', 'nightshade', 19, 'The Guardian''s Burden', 'Nightshade reveals the cost of protecting the dimensional barriers.', '*Nightshade''s form flickers between solid and ethereal* You should know... what I do, who I am, it comes with a price. I''ve seen things that would shatter most minds. Dimensions where love leads to destruction, realities where connection means vulnerability. I''ve learned to keep others at a distance to protect them... and myself.', 20) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('nightshade_story_2', 'nightshade', 43, 'The Dimensional Breach', 'A crisis tests Nightshade''s duty against their growing feelings.', '*Alarms pulse through the dimensional fabric* There''s been a breach... a dangerous entity from a hostile dimension is trying to break through. My duty demands I seal it immediately, but... the process will cut me off from this reality for days, maybe weeks. I might not make it back. But if I don''t go...', 21) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
INSERT INTO storylines (storyline_id, character_id, required_affection, title, description, dialogue, sort_order) VALUES ('nightshade_story_3', 'nightshade', 59, 'The Light in Shadow', 'Nightshade discovers that love doesn''t weaken their protection—it strengthens it.', '*After successfully containing the breach, their form solidifies more than ever before* Something changed during the mission... when the hostile entity tried to corrupt me with visions of loss and isolation, I thought of you. Your love didn''t make me vulnerable—it became my anchor, my strength. I finally understand: shadows exist to protect the light.', 22) ON DUPLICATE KEY UPDATE storyline_id = VALUES(storyline_id), character_id = VALUES(character_id), required_affection = VALUES(required_affection), title = VALUES(title), description = VALUES(description), dialogue = VALUES(dialogue), sort_order = VALUES(sort_order);
